import { inject } from '@angular/core';
import { CanActivateFn, Router } from '@angular/router';
import { map, take } from 'rxjs/operators';
import { SiteLanguage } from '../interfaces/language.interface';
import { SiteService } from '../services/site.service';

export const defaultLanguageGuard: CanActivateFn = () => {
  const router = inject(Router);
  const siteService = inject(SiteService);

  return siteService.getSiteConfig().pipe(
    take(1),
    map((siteConfig) => {
      const language = (siteConfig.defaultLanguage || 'it') as SiteLanguage;
      return router.parseUrl(`/${language}`);
    })
  );
};
