import { Component, Input } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { RouterLink } from '@angular/router';
import { SiteLanguage } from '../../interfaces/language.interface';
import { CookieConsentService, CookieConsentState } from '../../services/cookie-consent.service';

@Component({
  selector: 'app-cookie-banner',
  standalone: true,
  imports: [RouterLink],
  templateUrl: './cookie-banner.component.html',
  styleUrl: './cookie-banner.component.sass'
})
export class CookieBannerComponent {
  @Input() language: SiteLanguage = 'it';
  @Input() analyticsEnabled = false;

  protected consent: CookieConsentState | null = null;
  protected preferencesOpen = false;
  protected analyticsSelected = false;

  constructor(private readonly cookieConsentService: CookieConsentService) {
    this.cookieConsentService
      .getConsent$()
      .pipe(takeUntilDestroyed())
      .subscribe((consent) => {
        this.consent = consent;
        this.analyticsSelected = consent?.analytics ?? false;
      });

    this.cookieConsentService
      .getPreferencesRequests$()
      .pipe(takeUntilDestroyed())
      .subscribe(() => this.openPreferences());
  }

  protected get visible(): boolean {
    return this.preferencesOpen || (this.analyticsEnabled && !this.consent);
  }

  protected get privacyPath(): string {
    return this.language === 'it' ? '/it/privacy' : '/en/privacy';
  }

  protected get cookiePolicyPath(): string {
    return this.language === 'it' ? '/it/cookie-policy' : '/en/cookie-policy';
  }

  protected acceptAll(): void {
    this.cookieConsentService.saveConsent({ analytics: this.analyticsEnabled });
    this.preferencesOpen = false;
  }

  protected rejectOptional(): void {
    this.cookieConsentService.saveConsent({ analytics: false });
    this.preferencesOpen = false;
  }

  protected openPreferences(): void {
    this.analyticsSelected = this.consent?.analytics ?? false;
    this.preferencesOpen = true;
  }

  protected savePreferences(): void {
    this.cookieConsentService.saveConsent({
      analytics: this.analyticsEnabled && this.analyticsSelected
    });
    this.preferencesOpen = false;
  }

  protected updateAnalyticsSelection(event: Event): void {
    this.analyticsSelected = (event.target as HTMLInputElement).checked;
  }
}
